/**
 * Image-text-to-text pipeline using `AutoModelForImageTextToText`. This pipeline accepts
 * an image and a text prompt and generates text conditioned on both inputs. It is suited
 * for vision-language models such as SmolVLM, Qwen2-VL, Idefics3, and similar architectures
 * that combine visual understanding with text generation.
 *
 * **Example:** Describe an image w/ `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const image = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await pipe(image, 'Describe the image in one sentence.');
 * // [{ generated_text: 'Two cats are sitting on a couch.' }]
 * ```
 *
 * **Example:** Answer a question about an image w/ `Xenova/llava-1.5-7b-hf`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'Xenova/llava-1.5-7b-hf');
 * const image = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await pipe(image, 'How many cats are in the image?');
 * // [{ generated_text: 'There are two cats in the image.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(image, text, generate_kwargs = {}) {

        // Prepare the image(s) for processing
        const preparedImages = await prepareImages(image);

        // Use the processor to encode both text and images into model inputs.
        // The processor handles image feature extraction and text tokenization together.
        const inputs = await this.processor(text, preparedImages);

        // Generate output token IDs from the combined multimodal inputs
        const outputTokenIds = /** @type {Tensor} */(await this.model.generate({
            ...inputs,
            ...generate_kwargs,
        }));

        // Decode the generated token IDs back to text strings
        const decoded = this.tokenizer.batch_decode(outputTokenIds, {
            skip_special_tokens: true,
        }).map(x => ({ generated_text: x.trim() }));

        return decoded;
    }
}

